import React, { useState, useEffect } from 'react';
import { Target, AlertCircle, Edit2, Save, AlertTriangle } from 'lucide-react';
import { budgetAPI, expenseAPI } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

const BudgetSettings = () => {
  const { user } = useAuth();
  const [budgets, setBudgets] = useState([]);
  const [spending, setSpending] = useState([]);
  const [allExpenses, setAllExpenses] = useState([]);
  const [editing, setEditing] = useState(null);
  const [editAmount, setEditAmount] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [budgetsData, spendingData, allExpensesData] = await Promise.all([
        budgetAPI.getBudgets(),
        expenseAPI.getSpendingByCategory(),
        expenseAPI.getAll()
      ]);
      
      setBudgets(budgetsData);
      
      setSpending(spendingData);
      setAllExpenses(allExpensesData);
    } catch (error) {
      console.error('Error loading budget data:', error);
    }
  };

  const handleEdit = (category, amount) => {
    setEditing(category);
    setEditAmount(amount.toString());
  };

  const handleSave = async (category) => {
    try {
      await budgetAPI.setBudget({ category, amount: parseFloat(editAmount) });
      setEditing(null);
      loadData(); // Reload to show updated data
    } catch (error) {
      console.error('Error saving budget:', error);
    }
  };

  const getColor = (category) => {
    const colors = {
      food: '#3b82f6',
      transport: '#8b5cf6',
      entertainment: '#ec4899',
      shopping: '#f59e0b',
      other: '#10b981'
    };
    return colors[category.toLowerCase()] || '#6b7280';
  };

  const budgetData = budgets.map(budget => {
    const spent = spending.find(s => s._id.toLowerCase() === budget.category.toLowerCase())?.total || 0;
    return {
      category: budget.category,
      budget: budget.amount,
      spent,
      percentage: budget.amount > 0 ? ((spent / budget.amount) * 100).toFixed(1) : 0,
      color: getColor(budget.category)
    };
  });

  // Calculate overall totals
  const totalBudget = budgets.reduce((sum, b) => sum + b.amount, 0);
  const totalSpent = allExpenses.reduce((sum, exp) => sum + parseFloat(exp.amount), 0);
  const salary = user?.salary || 0;
  const isOverBudget = totalSpent > totalBudget;
  const isOverSalary = totalSpent > salary;

  return (
    <div className="budget-settings">
      <div className="page-header">
        <h1><Target size={24} /> Budget Settings</h1>
      </div>

      {/* Overall Budget Alerts */}
      {(isOverBudget || isOverSalary) && (
        <div className="overall-alert">
          <AlertTriangle size={20} color="red" />
          <strong>Budget Alert:</strong>
          {isOverBudget && ` Total spending ($${totalSpent}) exceeds total budget ($${totalBudget})!`}
          {isOverBudget && isOverSalary && ' | '}
          {isOverSalary && ` Total spending exceeds monthly salary ($${salary})!`}
        </div>
      )}

      <div className="budget-grid-cards">
        {budgetData.map((item) => (
          <div 
            key={item.category} 
            className="budget-card-colorful"
            style={{ '--card-color': item.color }}
          >
            <div className="budget-card-header">
              <h3 className="budget-category-name">{item.category}</h3>
              {editing === item.category ? (
                <input
                  type="number"
                  value={editAmount}
                  onChange={(e) => setEditAmount(e.target.value)}
                  style={{ width: '80px', fontSize: '18px' }}
                />
              ) : (
                <div className="budget-amount-main">${item.budget}</div>
              )}
            </div>
            
            <div className="budget-card-details">
              <div className="spent-amount">Spent: ${item.spent}</div>
              <div className="percentage-badge">{item.percentage}%</div>
            </div>

            <div className="budget-actions">
              {editing === item.category ? (
                <button onClick={() => handleSave(item.category)} className="btn-save">
                  <Save size={16} />
                </button>
              ) : (
                <button onClick={() => handleEdit(item.category, item.budget)} className="btn-edit">
                  <Edit2 size={16} />
                </button>
              )}
            </div>

            {parseFloat(item.percentage) > 90 && (
              <div className="over-budget-warning">
                <AlertCircle size={14} />
                Over budget!
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default BudgetSettings;
